    <rect x="186" y="50" width="158" height="80" rx="10" fill="#1a1005" stroke="#f7931a" stroke-width="1.6"/>
    <text x="265" y="86" fill="#fbbf24" text-anchor="middle" font-size="22" font-weight="800">+25bp</text>
    <text x="265" y="108" fill="#a1a1aa" text-anchor="middle" font-size="12.5">Tamaño de la subida (unánime)</text>
    <rect x="352" y="50" width="158" height="80" rx="10" fill="#1a0505" stroke="#f87171" stroke-width="1.6"/>
