    <text x="431" y="108" fill="#a1a1aa" text-anchor="middle" font-size="12.5">Prima kimchi (al 14 jul)</text>
    <rect x="518" y="50" width="162" height="80" rx="10" fill="#18181b" stroke="#3f3f46" stroke-width="1.3"/>
